SELECT tecoc.*
FROM esg.tb_emergency_control_org_chart tecoc
WHERE tecoc.comp_id = #{compId}

    AND write_year = #{writeYear}


    AND tecoc.chart_id = #{searchText}

order by tecoc.use_yn DESC, tecoc.confirm_at DESC, tecoc.updated_at DESC, tecoc.created_at DESC

SELECT tdt.*
FROM esg.tb_dataset_typeofemergencyroles tdt
WHERE tdt.comp_id = #{compId}
    AND tdt.type_id = #{typeId}
    AND tdt.use_yn = 'Y'
order by tdt.use_yn DESC, tdt.ord_seq ASC

mapper.update:
UPDATE esg.tb_emergency_control_org_chart SET
    confirm_yn = #{confirmYn},

    confirm_at = now(),


    confirm_at = null,

    updated_at = now(),
    updated_by = #{updatedBy}
WHERE comp_id = #{compId}
    AND chart_id = #{chartId}
    AND write_year = #{writeYear}

UPDATE esg.tb_emergency_control_org_chart SET
    chart_nm = #{chartNm},
    chart_data = #{chartData},
    org_count = #{orgCount},
    emergency_type = #{emergencyType},
    emergency_type_nm = #{emergencyTypeNm},
    use_yn = #{useYn},
    updated_at = now(),
    updated_by = #{updatedBy},
    chart_blob_data = #{chartBlobData}
WHERE comp_id = #{compId}
    AND chart_id = #{chartId}
    AND write_year = #{writeYear}

UPDATE esg.tb_emergency_control_org_chart SET
    use_yn = 'N',
    updated_at = now(),
    updated_by = #{updatedBy}
WHERE comp_id = #{compId}
    AND chart_id = #{chartId}
    AND write_year = #{writeYear}

